THE RISK:
{
 "id": "cra-conformity-clock",
 "title": "Cyber Resilience Act's Sept-2026 reporting and Dec-2027 conformity deadlines turn Year-1 large-operator tenders into CRA-readiness screens",
 "narrative": "An intelligent, networked PDU is a product-with-digital-elements under Regulation (EU) 2024/2847. Vulnerability-reporting obligations land 11 September 2026 — inside the venture's first 12 months — and full conformity (CRA CE marking, technical file, SBOM, coordinated vulnerability disclosure) lands 11 December 2027. Sophisticated buyers do not wait for legal deadlines: large operators are already writing CRA clauses into 2026 procurement frameworks. With CRA harmonized standards not yet published and notified-body capacity scarce, a pre-launch entrant cannot close a CRA-credible technical file inside the entry window. The serviceableFactor evidence names only EN 50600, ecodesign 2019/424 and CE/TÜV — the newest and most binding instrument for THIS product class is absent from the model entirely.",
 "category": "exogenous",
 "targetNodes": [
  "serviceableFactor",
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "CRA (Reg. 2024/2847) applies to networked PDUs as products-with-digital-elements: vulnerability-reporting duties from 11 Sep 2026, full conformity assessment (SBOM, secure-by-design technical file, CVD process) from 11 Dec 2027 — dates that overlap or immediately shadow the pre-launch entrant's first 12 months",
   "refs": [
    "profile:Product",
    "profile:Stage",
    "digest:serviceable-benchmark#c10"
   ]
  },
  {
   "step": "propagation",
   "text": "Large operators — the venture's declared first channel — front-load CRA-readiness (SBOM delivery, vulnerability-handling attestations) into 2026 RFPs; absent published harmonized standards, demonstrating conformity requires scarce notified-body engagement, so the entrant is screened out of frameworks the incumbents (with existing product-security organizations) pass",
   "refs": [
    "ledger:cust.operator-large",
    "digest:serviceable-benchmark#c12",
    "digest:serviceable-benchmark#c13"
   ]
  },
  {
   "step": "model-impact",
   "text": "The serviceableFactor haircut is justified by a three-instrument cert stack that omits the CRA; both reach (which demand is regulatory-clear for us) and Year-1 pace (how fast tenders can convert) are overstated for a networked product launching into the CRA transition window",
   "refs": [
    "ledger:serviceableFactor",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "The CRA reads as 'just another CE marking' and its headline deadline (Dec 2027) sits outside the 12-month window on paper — so it gets filed under 'later'. The kill path is buyer procurement clocks running 12–18 months ahead of legal deadlines, plus the reporting obligation that actually lands mid-window.",
 "expectedObviousness": "medium",
 "falsifier": "A sample of 2026 CE large-operator rack-power RFPs/framework agreements containing no CRA, SBOM or secure-development clauses, combined with confirmation that intelligent PDUs fall in the CRA default class with pure self-assessment and the entrant's CRA technical file is completable pre-launch.",
 "likelihood": {
  "value": 0.38,
  "rationale": "The dates and product-scope are enacted law, not forecast; the only uncertainty is how fast CE operators pull CRA requirements into procurement, and regulated buyers historically front-run compliance deadlines with supplier asks. [evidence revision: The regulatory dates and scope are confirmed enacted law, strengthening the trigger. But the mechanism's severity hinges on notified-body scarcity screening out the entrant, which only bites if the PDU is Important/Critical class. Evidence indicates ~90% of products are Default and use self-assessment with no notified body — and no harmonized standard is needed to complete a self-assessed technical file. Absent proof the PDU is a higher class, the screen-out is weaker than the narrative asserts, and there is no direct evidence 2026 RFPs already carry CRA clauses. Nudge down modestly from 0.45.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "serviceableFactor",
   "op": "scale",
   "value": 0.85,
   "note": "CRA-gated demand (security-clause frameworks) drops out of the reachable set until the conformity file closes"
  },
  {
   "nodeId": "obtainableFactor",
   "op": "set",
   "value": 0.02,
   "note": "tender cycles extend while CRA evidence is assembled; Year-1 pace slows below the 3% mid-band"
  }
 ],
 "indicators": [
  {
   "signal": "CRA/SBOM/secure-development clauses appearing in operator rack-power procurement",
   "where": "TED (Tenders Electronic Daily) notices; supplier-requirement pages of Equinix/NTT/Vantage/Data4 procurement portals",
   "threshold": "≥2 CE operator RFPs requiring SBOM delivery or CRA conformity declaration before Dec 2026",
   "updates": "increases"
  },
  {
   "signal": "Publication status of CRA harmonized standards (CEN/CENELEC JTC 13 work programme)",
   "where": "OJEU harmonized-standards listings; CEN/CENELEC JTC 13 docket",
   "threshold": "hENs for horizontal CRA requirements slipping past mid-2026, forcing notified-body routes",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission a CRA classification and gap assessment (default vs important-product class, self-assessment vs notified-body route) for the PDU's connectivity stack",
   "type": "information",
   "voiNodeId": "serviceableFactor",
   "note": "determines whether the conformity clock even fits the entry window"
  },
  {
   "action": "Stand up SBOM generation and an IEC 62443-4-1-aligned secure development lifecycle now, and pre-book a notified-body assessment slot before the 2026 queue forms",
   "type": "operational",
   "voiNodeId": null,
   "note": null
  },
  {
   "action": "Sequence first sales through an OEM/integrator whose CRA-compliant product wrapper covers the integrated PDU while the entrant's own file matures",
   "type": "strategic",
   "voiNodeId": null,
   "note": null
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "CRA Product Classification: Default, Important, Critical",
   "sourceType": "industry-report",
   "publisher": "CRA Evidence",
   "date": "2026-05-08",
   "excerpt": "Default products can usually use internal control, based on Module A. ... about 90% of products fall into the Default category.",
   "url": "https://craevidence.com/cra-compliance/product-classification",
   "attached": true
  },
  {
   "title": "What Are CRA Harmonised Standards? Status and Tracker",
   "sourceType": "industry-report",
   "publisher": "CRA Evidence",
   "date": "2026-06-04",
   "excerpt": "No CRA harmonised standard is published in the Official Journal yet (as of 4 June 2026), so the Article 27 presumption of conformity is not available for any product category.",
   "url": "https://craevidence.com/cra-compliance/harmonised-standards-status",
   "attached": true
  },
  {
   "title": "EU Cyber Resilience Act: CRA Compliance Guide 2026",
   "sourceType": "industry-report",
   "publisher": "Cloudsmith",
   "date": "2026-06-11",
   "excerpt": "On September 11, 2026, vulnerability reporting obligations go live... December 11, 2027, is the full compliance deadline, covering all remaining CRA software requirements, including SBOMs, secure-by-design, CE marking, and technical documentation for any new product placed on the EU market.",
   "url": "https://cloudsmith.com/blog/the-eu-cyber-resilience-act-what-engineering-teams-need-to-do-to-be-compliant",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://norppa.io/guides/cyber-resilience-act",
   "stance": "supports",
   "quote": "its first reporting duties begin in September 2026, and from December 2027 a product that does not meet its requirements cannot legally be sold in the EU"
  },
  {
   "url": "https://cloudsmith.com/blog/the-eu-cyber-resilience-act-what-engineering-teams-need-to-do-to-be-compliant",
   "stance": "supports",
   "quote": "On September 11, 2026, vulnerability reporting obligations go live; manufacturers must report actively exploited vulnerabilities to ENISA within 24 hours, even for products already on the market. December 11, 2027, is the full compliance deadline, covering all remaining CRA software requirements, including SBOMs, secure-by-design, CE marking, and technical documentation"
  },
  {
   "url": "https://craevidence.com/cra-compliance/harmonised-standards-status",
   "stance": "supports",
   "quote": "No CRA harmonised standard is published in the Official Journal yet (as of 4 June 2026), so the Article 27 presumption of conformity is not available for any product category."
  },
  {
   "url": "https://craevidence.com/cra-compliance/product-classification",
   "stance": "contradicts",
   "quote": "Default products can usually use internal control. Important and Critical products may need a Notified Body"
  },
  {
   "url": "https://theembeddedkit.io/blog/product-categories-cyber-resilience-act/",
   "stance": "contradicts",
   "quote": "All products that are not explicitly listed as either important or critical are in this category. It is estimated that this represents around 90% of all products with a digital element. For these products, compliance with the Cyber Resilience Act is done through a self-assessment."
  }
 ]
}

